Here are the public test cases for feature10_attributes:
{
  "description": "Maintain a small set of named flags. 'add' inserts a flag, 'remove' deletes it, 'clear' empties the set, and 'contains' queries membership; adding then removing leaves it absent, and clearing removes everything. Output echoes each mutating operation and renders each query as 'contains[<flag>]=<true|false>'.",
  "cases": [
    {
      "input": {
        "feature": "attributes",
        "operations": [
          {
            "op": "add",
            "flag": "SYNTHETIC"
          },
          {
            "op": "contains",
            "flag": "SYNTHETIC"
          }
        ]
      },
      "expected_output": "add=SYNTHETIC\ncontains[SYNTHETIC]=true\n"
    },
    {
      "input": {
        "feature": "attributes",
        "operations": [
          {
            "op": "add",
            "flag": "SYNTHETIC"
          },
          {
            "op": "remove",
            "flag": "SYNTHETIC"
          },
          {
            "op": "contains",
            "flag": "SYNTHETIC"
          }
        ]
      },
      "expected_output": "add=SYNTHETIC\nremove=SYNTHETIC\ncontains[SYNTHETIC]=false\n"
    },
    {
      "input": {
        "feature": "attributes",
        "operations": [
          {
            "op": "add",
            "flag": "SYNTHETIC"
          },
          {
            "op": "add",
            "flag": "LOOP_START"
          },
          {
            "op": "clear"
          },
          {
            "op": "contains",
            "flag": "SYNTHETIC"
          },
          {
            "op": "contains",
            "flag": "LOOP_START"
          }
        ]
      },
      "expected_output": "add=SYNTHETIC\nadd=LOOP_START\nclear\ncontains[SYNTHETIC]=false\ncontains[LOOP_START]=false\n"
    }
  ]
}

Here are the public test cases for feature12_certificate:
{
  "description": "Decode an X.509 certificate (provided as base64-encoded DER bytes) and extract human-readable details. The 'signature' field reports the signature algorithm name and its object identifier; the 'public_key' field reports the key algorithm and, for an RSA key, its exponent, modulus bit-size and full modulus value. Output is one 'label: value' line per detail.",
  "cases": [
    {
      "input": {
        "feature": "certificate",
        "field": "signature",
        "der_base64": ""
      },
      "expected_output": "Signature type: SHA256withRSA\nSignature OID: 1.2.840.113549.1.1.11\n"
    },
    {
      "input": {
        "feature": "certificate",
        "field": "public_key",
        "der_base64": ""
      },
      "expected_output": "Public key type: RSA\nExponent: 65537\nModulus size (bits): 2048\nModulus: \n"
    },
    {
      "input": {
        "feature": "certificate",
        "field": "signature",
        "der_base64": ""
      },
      "expected_output": "Signature type: SHA1withDSA\nSignature OID: 1.2.840.10040.4.3\n"
    }
  ]
}

Here are the public test cases for feature1_string_escape:
{
  "description": "Render a raw text value as a double-quoted literal: control characters become two-character escape sequences (\\n, \\t, \\r, \\b, \\f), backslash and double-quote are escaped, a single-quote is left as-is, and (with unicode escaping on) any character at or above code point 127 becomes a \\uXXXX sequence. Output is the quoted literal on an 'escaped=' line.",
  "cases": [
    {
      "input": {
        "feature": "string_escape",
        "escape_unicode": true,
        "input": ""
      },
      "expected_output": "escaped=\"\"\n"
    },
    {
      "input": {
        "feature": "string_escape",
        "escape_unicode": true,
        "input": "\n"
      },
      "expected_output": "escaped=\"\\n\"\n"
    },
    {
      "input": {
        "feature": "string_escape",
        "escape_unicode": true,
        "input": "\\"
      },
      "expected_output": "escaped=\"\\\\\"\n"
    },
    {
      "input": {
        "feature": "string_escape",
        "escape_unicode": true,
        "input": "\""
      },
      "expected_output": "escaped=\"\\\"\"\n"
    },
    {
      "input": {
        "feature": "string_escape",
        "escape_unicode": true,
        "input": "ሴ"
      },
      "expected_output": "escaped=\"\\u1234\"\n"
    }
  ]
}
